import { StructuredQuestion } from '../types';

export const builderBank: Record<number, StructuredQuestion[]> = {
  1: [ // Forces and Motion
    { marks: 1, q: "Identify whether 'Weight' is a vector or a scalar quantity.", a: "Vector quantity.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification of vector." },
    { marks: 1, q: "State the standard unit for acceleration.", a: "m/s² (metres per second squared).\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 1, q: "Define the term 'Scalar'.", a: "A quantity that has magnitude only, and no direction.\n\n*Marking Scheme:*\n- 1 Mark: Mention of magnitude without direction." },
    { marks: 1, q: "Identify the scalar quantity from this list: Acceleration, Force, Mass, Momentum.", a: "Mass.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification of mass." },
    { marks: 1, q: "State the formula relating average speed, distance moved, and time taken.", a: "Average speed = Distance moved / Time taken\n\n*Marking Scheme:*\n- 1 Mark: Correct formula." },
    { marks: 1, q: "State the standard unit for the Moment of a force.", a: "Newton-metres (N m).\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 1, q: "Define 'Acceleration'.", a: "The rate of change of velocity (or change in velocity per unit time).\n\n*Marking Scheme:*\n- 1 Mark: Definition mentioning rate or change per time." },
    { marks: 1, q: "Is friction a contact or non-contact force?", a: "Contact force.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "State the Principle of Moments for an object in equilibrium.", a: "The total clockwise moment equals the total anticlockwise moment about a pivot.\n\n*Marking Scheme:*\n- 1 Mark: Stating equality of CW and ACW moments." },
    { marks: 1, q: "What is meant by the 'limit of proportionality' of a spring?", a: "The point beyond which extension is no longer proportional to force (Hooke's Law no longer applies).\n\n*Marking Scheme:*\n- 1 Mark: Reference to non-proportionality." },
    { marks: 2, q: "A cyclist travels 450 metres in 30 seconds. Calculate their average speed.", a: "Speed = Distance / Time\nSpeed = 450 / 30\nSpeed = 15 m/s\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution into formula.\n- 1 Mark: Correct answer with units." },
    { marks: 2, q: "A car accelerates from 5 m/s to 25 m/s in 4 seconds. Calculate its acceleration.", a: "a = (v - u) / t\na = (25 - 5) / 4\na = 20 / 4\na = 5 m/s²\n\n*Marking Scheme:*\n- 1 Mark: Correct calculation of change in velocity (20).\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Calculate the distance a train travels if it moves at a constant speed of 12 m/s for 2 minutes.", a: "Distance = Speed × Time\nTime = 2 × 60 = 120s\nDistance = 12 × 120\nDistance = 1440 m\n\n*Marking Scheme:*\n- 1 Mark: Conversion of minutes to seconds.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "An object is dropped and accelerates at 10 m/s². How fast is it moving after 3.5 seconds?", a: "v = u + (a × t)\nv = 0 + (10 × 3.5)\nv = 35 m/s\n\n*Marking Scheme:*\n- 1 Mark: Identification of initial velocity as zero or correct use of a × t.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "How long does it take for a bird flying at 8 m/s to cover a distance of 1.2 km?", a: "Time = Distance / Speed\nDistance = 1200 m\nTime = 1200 / 8\nTime = 150 s\n\n*Marking Scheme:*\n- 1 Mark: Conversion of km to m.\n- 1 Mark: Final answer in seconds." },
    { marks: 2, q: "Calculate the time taken for a radio signal (speed 3 × 10⁸ m/s) to travel 600 km.", a: "t = d / v\nd = 600,000 m\nt = 600,000 / 300,000,000\nt = 0.002 s (or 2 × 10⁻³ s)\n\n*Marking Scheme:*\n- 1 Mark: Conversion of km to m.\n- 1 Mark: Final calculation." },
    { marks: 2, q: "A car slows from 30 m/s to 10 m/s in 5 seconds. Calculate the deceleration.", a: "a = (10 - 30) / 5 = -20 / 5 = -4 m/s²\nDeceleration = 4 m/s²\n\n*Marking Scheme:*\n- 1 Mark: Correct change in velocity calculation.\n- 1 Mark: Correct magnitude for deceleration." },
    { marks: 2, q: "Calculate the moment produced by a 5 N force acting at a distance of 20 cm from a pivot.", a: "M = F × d\nd = 0.2 m\nM = 5 × 0.2\nM = 1 N m\n\n*Marking Scheme:*\n- 1 Mark: Conversion of cm to m.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Calculate the force required to stretch a spring (k = 100 N/m) by 5 cm.", a: "F = k × x\nx = 0.05 m\nF = 100 × 0.05\nF = 5 N\n\n*Marking Scheme:*\n- 1 Mark: Conversion of cm to m.\n- 1 Mark: Calculation of Force." },
    { marks: 2, q: "What is the velocity of a 2 kg mass if it has a momentum of 10 kg m/s?", a: "v = p / m\nv = 10 / 2\nv = 5 m/s\n\n*Marking Scheme:*\n- 1 Mark: Rearrangement of p=mv.\n- 1 Mark: Final answer with units." },
    { marks: 3, q: "A car of mass 1200 kg accelerates from rest to 20 m/s in 8 seconds. Calculate the resultant force acting on the car.", a: "1. Calculate acceleration: a = (v - u) / t = (20 - 0) / 8 = 2.5 m/s²\n2. Calculate Force: F = m × a = 1200 × 2.5 = 3000 N\n\n*Marking Scheme:*\n- 1 Mark: Correct calculation of acceleration (2.5).\n- 1 Mark: Correct use of F = ma.\n- 1 Mark: Final answer with units (3000 N)." },
    { marks: 3, q: "Explain the difference between 'thinking distance' and 'braking distance', and state one factor that affects each.", a: "Thinking distance is the distance traveled during the driver's reaction time. Braking distance is the distance traveled while the brakes are applied. \nFactor for thinking: Tiredness/Alcohol/Drugs. \nFactor for braking: Road conditions (icy/wet)/Tire condition.\n\n*Marking Scheme:*\n- 1 Mark: Correct definitions of both distances.\n- 1 Mark: Correct factor for thinking distance.\n- 1 Mark: Correct factor for braking distance." },
    { marks: 3, q: "A 5 kg object is taken from Earth (g = 10 N/kg) to the Moon (g = 1.6 N/kg). Calculate its weight on Earth and its weight on the Moon.", a: "Weight on Earth = m × g = 5 × 10 = 50 N\nWeight on Moon = m × g = 5 × 1.6 = 8 N\n\n*Marking Scheme:*\n- 1 Mark: Correct calculation for Earth (50 N).\n- 1 Mark: Correct calculation for Moon (8 N).\n- 1 Mark: Correct units used for both." },
    { marks: 3, q: "Describe the motion of an object falling through a fluid until it reaches terminal velocity.", a: "Initially, the object accelerates because weight is greater than air resistance. As speed increases, air resistance increases. Eventually, air resistance equals weight, resultant force is zero, and the object moves at constant (terminal) velocity.\n\n*Marking Scheme:*\n- 1 Mark: Initial acceleration due to weight > resistance.\n- 1 Mark: Resistance increases with speed.\n- 1 Mark: Terminal velocity reached when forces are balanced." },
    { marks: 3, q: "A force of 15 N is applied to a spring, causing it to stretch from 10 cm to 13 cm. Calculate the spring constant (k) in N/m.", a: "Extension (x) = 13 - 10 = 3 cm = 0.03 m\nk = F / x = 15 / 0.03 = 500 N/m\n\n*Marking Scheme:*\n- 1 Mark: Correct extension in metres (0.03 m).\n- 1 Mark: Correct rearrangement k = F/x.\n- 1 Mark: Final answer with units (500 N/m)." },
    { marks: 3, q: "Explain how a seatbelt reduces the risk of injury during a car crash in terms of momentum and force.", a: "A seatbelt increases the time taken for the passenger to stop. Since Force = Change in Momentum / Time, increasing the time reduces the impact force acting on the body.\n\n*Marking Scheme:*\n- 1 Mark: Mention of increasing the time of impact.\n- 1 Mark: Reference to the formula F = Δp / t.\n- 1 Mark: Conclusion that force is reduced." },
    { marks: 3, q: "A 0.5 kg ball moving at 10 m/s hits a wall and bounces back at 8 m/s in the opposite direction. Calculate the change in momentum.", a: "Initial p = 0.5 × 10 = 5 kg m/s\nFinal p = 0.5 × (-8) = -4 kg m/s\nChange = -4 - 5 = -9 kg m/s (Magnitude is 9)\n\n*Marking Scheme:*\n- 1 Mark: Correct initial momentum (5).\n- 1 Mark: Correct final momentum with opposite sign (-4).\n- 1 Mark: Correct calculation of change (9 kg m/s)." },
    { marks: 3, q: "Explain why a wide base and a low center of gravity make an object more stable.", a: "A low center of gravity means the object must be tilted further before the line of action of its weight falls outside the base. A wide base also makes it harder for the line of action to fall outside the base.\n\n*Marking Scheme:*\n- 1 Mark: Mention of the line of action of weight.\n- 1 Mark: Reference to the base of the object.\n- 1 Mark: Explanation of tilting/tipping point." },
    { marks: 3, q: "State the difference between a vector and a scalar quantity, and give two examples of each.", a: "Scalars have magnitude only; Vectors have magnitude and direction. \nScalars: Mass, Speed, Distance, Energy. \nVectors: Force, Velocity, Acceleration, Momentum.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition of both.\n- 1 Mark: Two correct scalar examples.\n- 1 Mark: Two correct vector examples." },
    { marks: 3, q: "A velocity-time graph shows a car accelerating from 0 to 10 m/s in 5s, then moving at 10 m/s for 10s. Calculate the total distance traveled.", a: "Distance 1 (Triangle) = ½ × 5 × 10 = 25 m\nDistance 2 (Rectangle) = 10 × 10 = 100 m\nTotal = 125 m\n\n*Marking Scheme:*\n- 1 Mark: Area of triangle (25 m).\n- 1 Mark: Area of rectangle (100 m).\n- 1 Mark: Correct total distance (125 m)." }
  ],
  2: [ // Electricity
    { marks: 1, q: "State the standard unit for electrical charge.", a: "Coulomb (C)\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 1, q: "Name the instrument used to measure electric current.", a: "Ammeter\n\n*Marking Scheme:*\n- 1 Mark: Correct identification of the device." },
    { marks: 1, q: "What color is the 'Live' wire in a standard UK three-pin plug?", a: "Brown\n\n*Marking Scheme:*\n- 1 Mark: Correct color." },
    { marks: 1, q: "Define 'Electric Current'.", a: "The rate of flow of charge (or flow of electrons per second).\n\n*Marking Scheme:*\n- 1 Mark: Mention of 'rate' or 'flow' of charge." },
    { marks: 1, q: "How does the resistance of a thermistor change when its temperature increases?", a: "The resistance decreases.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification of the decrease." },
    { marks: 1, q: "Define 'Potential Difference' in terms of energy.", a: "The energy transferred per unit charge passing between two points.\n\n*Marking Scheme:*\n- 1 Mark: Reference to energy per charge or Joules per Coulomb." },
    { marks: 1, q: "State the function of the Earth wire in a domestic appliance.", a: "It provides a low resistance path to ground to prevent electric shocks if the casing becomes live.\n\n*Marking Scheme:*\n- 1 Mark: Reference to safety, low resistance path, or grounding." },
    { marks: 1, q: "Identify the circuit component that only allows current to flow in one direction.", a: "Diode\n\n*Marking Scheme:*\n- 1 Mark: Correct component name." },
    { marks: 1, q: "What is the difference between AC and DC current in terms of direction?", a: "DC flows in one direction only, while AC constantly reverses direction.\n\n*Marking Scheme:*\n- 1 Mark: Mention of constant vs changing direction." },
    { marks: 1, q: "State the standard unit for electrical resistance.", a: "Ohm (Ω)\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 2, q: "A current of 0.5 A flows through a lamp for 2 minutes. Calculate the charge that passes through the lamp.", a: "Q = I × t\nt = 2 × 60 = 120 s\nQ = 0.5 × 120 = 60 C\n\n*Marking Scheme:*\n- 1 Mark: Conversion of time to seconds.\n- 1 Mark: Final answer with units (60 C)." },
    { marks: 2, q: "Calculate the resistance of a toaster that carries a current of 5 A when connected to a 230 V mains supply.", a: "R = V / I\nR = 230 / 5\nR = 46 Ω\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution into R = V/I.\n- 1 Mark: Final answer with units (46 Ω)." },
    { marks: 2, q: "A 1.5 kW heater is used for 30 minutes. Calculate the energy transferred in kilowatt-hours (kWh).", a: "E = P × t\nt = 0.5 hours\nE = 1.5 × 0.5 = 0.75 kWh\n\n*Marking Scheme:*\n- 1 Mark: Conversion of time to hours.\n- 1 Mark: Final answer with units (0.75 kWh)." },
    { marks: 2, q: "Explain why a plastic comb becomes charged when rubbed with a dry cloth.", a: "Friction between the comb and cloth causes electrons to be transferred from one to the other. Plastic is an insulator so the charge remains on the surface.\n\n*Marking Scheme:*\n- 1 Mark: Mention of electron transfer.\n- 1 Mark: Mention of friction or insulator property." },
    { marks: 2, q: "State two advantages of using a circuit breaker instead of a fuse.", a: "1. Circuit breakers can be reset easily.\n2. They operate much faster than fuses.\n\n*Marking Scheme:*\n- 1 Mark: Mention of being resettable.\n- 1 Mark: Mention of speed of operation." },
    { marks: 2, q: "A circuit has two 10 Ω resistors in series. Calculate the total resistance.", a: "R_total = R1 + R2\nR_total = 10 + 10 = 20 Ω\n\n*Marking Scheme:*\n- 1 Mark: Correct addition of resistances.\n- 1 Mark: Final answer with units (20 Ω)." },
    { marks: 2, q: "Describe how the resistance of an LDR changes as light intensity increases.", a: "As light intensity increases, the resistance of the LDR decreases.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification of the decrease.\n- 1 Mark: Mention of the inverse relationship." },
    { marks: 2, q: "Calculate the power of a device that uses 12 V and carries a current of 3 A.", a: "P = I × V\nP = 3 × 12 = 36 W\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution into P=IV.\n- 1 Mark: Final answer with units (36 W)." },
    { marks: 2, q: "Explain what is meant by 'double insulation'.", a: "The appliance has a plastic casing and the internal wires are also insulated, so there is no metal part that can become live.\n\n*Marking Scheme:*\n- 1 Mark: Mention of plastic/insulating casing.\n- 1 Mark: Mention of no need for an earth wire." },
    { marks: 2, q: "A fuse is rated at 13 A. Explain why it would not be suitable for a device that normally uses 2 A.", a: "A 13 A fuse is too high; if a fault occurs, a current much larger than 2 A could flow without the fuse blowing, which could cause a fire.\n\n*Marking Scheme:*\n- 1 Mark: Mention that the rating is too high.\n- 1 Mark: Reference to fire risk or lack of protection." },
    { marks: 3, q: "Explain how a fuse protects a circuit.", a: "If the current becomes too high, the thin wire inside the fuse heats up and melts. This breaks the circuit and stops the flow of electricity, preventing fire or damage.\n\n*Marking Scheme:*\n- 1 Mark: Mention of wire heating/melting.\n- 1 Mark: Mention of breaking the circuit.\n- 1 Mark: Reference to high current/safety." },
    { marks: 3, q: "A 230 V kettle has a power rating of 2.5 kW. Calculate the current flowing through it and suggest a suitable fuse (3A, 5A, or 13A).", a: "1. I = P / V = 2500 / 230 = 10.87 A\n2. Suitable fuse: 13 A\n\n*Marking Scheme:*\n- 1 Mark: Conversion of kW to W (2500).\n- 1 Mark: Correct calculation of current (10.87 A).\n- 1 Mark: Selection of 13 A fuse." },
    { marks: 3, q: "Explain why the IV graph for a filament lamp is a curve and not a straight line.", a: "As current increases, the temperature of the filament increases. This causes the metal ions to vibrate more, increasing the resistance, which reduces the rate of current increase.\n\n*Marking Scheme:*\n- 1 Mark: Temperature increases with current.\n- 1 Mark: Resistance increases with temperature.\n- 1 Mark: Resulting in a non-linear (curved) relationship." },
    { marks: 3, q: "Compare series and parallel circuits for use in domestic lighting.", a: "In parallel, lights can be switched independently and if one bulb blows, the others stay on. In series, all lights must be on together and if one blows, the whole circuit breaks.\n\n*Marking Scheme:*\n- 1 Mark: Independent switching in parallel.\n- 1 Mark: Reliability (one blows, others stay on) in parallel.\n- 1 Mark: Contrast with series behavior." },
    { marks: 3, q: "Calculate the energy transferred when a 12 V battery moves 500 C of charge through a circuit.", a: "E = Q × V\nE = 500 × 12\nE = 6000 J (or 6 kJ)\n\n*Marking Scheme:*\n- 1 Mark: Correct formula E = QV.\n- 1 Mark: Correct calculation (6000).\n- 1 Mark: Correct units (Joules)." },
    { marks: 3, q: "Explain the danger of static electricity when refuelling an aircraft.", a: "Fuel flowing through pipes can build up static charge by friction. A spark could jump between the nozzle and the plane, igniting the fuel and causing an explosion.\n\n*Marking Scheme:*\n- 1 Mark: Charge build-up due to friction.\n- 1 Mark: Risk of a spark.\n- 1 Mark: Ignition of fuel/explosion risk." },
    { marks: 3, q: "Describe how an inkjet printer uses static electricity to direct ink drops.", a: "Ink drops are given a charge. They pass between two deflecting plates with opposite charges. By changing the voltage on the plates, the drops are steered to the correct place on the paper.\n\n*Marking Scheme:*\n- 1 Mark: Charging the ink drops.\n- 1 Mark: Use of charged deflecting plates.\n- 1 Mark: Steering/deflection of the drops." },
    { marks: 3, q: "A resistor has 5 V across it and a current of 0.2 A. Calculate the power dissipated and the energy transferred in 1 minute.", a: "1. P = I × V = 0.2 × 5 = 1 W\n2. E = P × t = 1 × 60 = 60 J\n\n*Marking Scheme:*\n- 1 Mark: Correct power calculation (1 W).\n- 1 Mark: Correct time conversion (60 s).\n- 1 Mark: Correct energy calculation (60 J)." },
    { marks: 3, q: "Explain how earthing a metal-cased appliance prevents an electric shock.", a: "If the live wire touches the metal case, a large current flows through the earth wire to the ground. This large current blows the fuse, disconnecting the supply.\n\n*Marking Scheme:*\n- 1 Mark: Current flows through earth wire to ground.\n- 1 Mark: Large current blows the fuse.\n- 1 Mark: Circuit is disconnected/safe." },
    { marks: 3, q: "Calculate the total resistance of a 4 Ω and a 6 Ω resistor connected in series, and the current if connected to a 12 V supply.", a: "1. R_total = 4 + 6 = 10 Ω\n2. I = V / R = 12 / 10 = 1.2 A\n\n*Marking Scheme:*\n- 1 Mark: Correct total resistance (10 Ω).\n- 1 Mark: Correct use of I = V/R.\n- 1 Mark: Final current with units (1.2 A)." }
  ],
  3: [ // Waves - Edexcel IGCSE
    { marks: 1, q: "State the formula relating wave speed, frequency, and wavelength.", a: "v = f × λ (Wave speed = frequency × wavelength)\n\n*Marking Scheme:*\n- 1 Mark: Correct formula." },
    { marks: 1, q: "State the standard unit for frequency.", a: "Hertz (Hz)\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 1, q: "Define the term 'Wavelength'.", a: "The distance from one point on a wave to the same point on the next wave (e.g., peak to peak).\n\n*Marking Scheme:*\n- 1 Mark: Definition mentioning distance between identical points." },
    { marks: 1, q: "What is the range of human hearing?", a: "20 Hz to 20,000 Hz (or 20 kHz).\n\n*Marking Scheme:*\n- 1 Mark: Correct range." },
    { marks: 1, q: "State the law of reflection.", a: "Angle of incidence = Angle of reflection.\n\n*Marking Scheme:*\n- 1 Mark: Correct statement of equality." },
    { marks: 1, q: "Which part of the EM spectrum has the highest frequency?", a: "Gamma rays.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "State the speed of all electromagnetic waves in a vacuum.", a: "3 × 10⁸ m/s (or 300,000,000 m/s).\n\n*Marking Scheme:*\n- 1 Mark: Correct speed." },
    { marks: 1, q: "Define 'Refractive Index'.", a: "The ratio of the speed of light in a vacuum to the speed of light in a medium (or n = sin i / sin r).\n\n*Marking Scheme:*\n- 1 Mark: Correct definition or formula." },
    { marks: 1, q: "Define the term 'Amplitude'.", a: "The maximum displacement of a point on a wave from its undisturbed position.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition mentioning maximum displacement." },
    { marks: 1, q: "State the formula relating frequency and time period.", a: "f = 1 / T (Frequency = 1 / Time period)\n\n*Marking Scheme:*\n- 1 Mark: Correct formula." },
    { marks: 2, q: "Explain the difference between transverse and longitudinal waves.", a: "In transverse waves, vibrations are perpendicular to the direction of energy transfer. In longitudinal waves, vibrations are parallel to the direction of energy transfer.\n\n*Marking Scheme:*\n- 1 Mark: Correct description of transverse.\n- 1 Mark: Correct description of longitudinal." },
    { marks: 2, q: "A wave has a frequency of 50 Hz and a wavelength of 2 m. Calculate its speed.", a: "v = f × λ\nv = 50 × 2\nv = 100 m/s\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "State two properties that are common to all electromagnetic waves.", a: "1. They are all transverse waves.\n2. They all travel at the same speed in a vacuum (3 × 10⁸ m/s).\n\n*Marking Scheme:*\n- 1 Mark: Transverse property.\n- 1 Mark: Speed in vacuum property." },
    { marks: 2, q: "Explain what is meant by 'Critical Angle'.", a: "The angle of incidence above which total internal reflection occurs (when light travels from a more dense to a less dense medium).\n\n*Marking Scheme:*\n- 1 Mark: Reference to the angle of incidence.\n- 1 Mark: Mention of TIR or the condition of density." },
    { marks: 2, q: "Calculate the refractive index of a glass block if the angle of incidence is 45° and the angle of refraction is 28°.", a: "n = sin i / sin r\nn = sin(45) / sin(28)\nn = 0.707 / 0.469 = 1.51\n\n*Marking Scheme:*\n- 1 Mark: Correct use of Snell's Law.\n- 1 Mark: Final answer (approx 1.5)." },
    { marks: 2, q: "State two uses of infrared radiation.", a: "1. Remote controls.\n2. Night vision equipment / Cooking / Heaters.\n\n*Marking Scheme:*\n- 1 Mark: First correct use.\n- 1 Mark: Second correct use." },
    { marks: 2, q: "Describe the danger of excessive exposure to ultraviolet (UV) radiation.", a: "UV radiation can cause skin cancer and damage to the eyes (cataracts).\n\n*Marking Scheme:*\n- 1 Mark: Mention of skin cancer.\n- 1 Mark: Mention of eye damage." },
    { marks: 2, q: "A sound wave travels 1.5 km in 4.5 seconds. Calculate the speed of sound.", a: "Speed = Distance / Time\nDistance = 1500 m\nSpeed = 1500 / 4.5 = 333.3 m/s\n\n*Marking Scheme:*\n- 1 Mark: Conversion of km to m.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Explain why sound travels faster in solids than in gases.", a: "Particles in solids are much closer together than in gases, so vibrations can be passed from particle to particle more quickly.\n\n*Marking Scheme:*\n- 1 Mark: Mention of particle proximity.\n- 1 Mark: Reference to quicker transfer of vibrations." },
    { marks: 2, q: "State the formula relating critical angle (c) and refractive index (n).", a: "sin c = 1 / n\n\n*Marking Scheme:*\n- 1 Mark: Correct formula.\n- 1 Mark: Identification of terms." },
    { marks: 3, q: "Describe an experiment to measure the speed of sound in air.", a: "Two people stand a measured distance apart (e.g., 100m). One person bangs two blocks together. The other starts a stopwatch when they see the flash and stops it when they hear the sound. Speed = Distance / Time.\n\n*Marking Scheme:*\n- 1 Mark: Mention of measuring a large distance.\n- 1 Mark: Method involving seeing vs hearing (timing).\n- 1 Mark: Use of speed = distance / time." },
    { marks: 3, q: "Explain how optical fibres use total internal reflection to transmit data.", a: "Light enters the fibre at an angle greater than the critical angle. It hits the boundary between the core and cladding and reflects back into the core. This repeats down the length of the fibre.\n\n*Marking Scheme:*\n- 1 Mark: Angle of incidence > critical angle.\n- 1 Mark: Reflection at the boundary.\n- 1 Mark: Repeated reflection (trapping light in core)." },
    { marks: 3, q: "Describe the Doppler Effect as observed when a car sounding its horn moves towards and then away from a stationary observer.", a: "As the car approaches, wave fronts are compressed, wavelength decreases, and frequency (pitch) increases. As it moves away, wave fronts are stretched, wavelength increases, and frequency decreases.\n\n*Marking Scheme:*\n- 1 Mark: Higher pitch/frequency when approaching.\n- 1 Mark: Lower pitch/frequency when receding.\n- 1 Mark: Explanation involving compression/stretching of wavefronts." },
    { marks: 3, q: "Explain the conditions required for Total Internal Reflection (TIR) to occur.", a: "1. The light must be traveling from a more optically dense medium to a less optically dense medium.\n2. The angle of incidence must be greater than the critical angle.\n\n*Marking Scheme:*\n- 1 Mark: More dense to less dense.\n- 1 Mark: Angle of incidence > critical angle.\n- 1 Mark: Mention of light/wave behavior." },
    { marks: 3, q: "A prism splits white light into a spectrum. Explain why this happens.", a: "White light is made of different colors. Each color has a different wavelength and travels at a different speed in glass. Therefore, each color refracts by a different amount, causing them to spread out.\n\n*Marking Scheme:*\n- 1 Mark: Different colors have different wavelengths.\n- 1 Mark: Different speeds in glass/medium.\n- 1 Mark: Different amounts of refraction (dispersion)." },
    { marks: 3, q: "Describe the uses and dangers of X-rays in medicine.", a: "Uses: To observe internal bone structures or treat cancer. Dangers: X-rays are ionising radiation which can cause cell mutations and lead to cancer.\n\n*Marking Scheme:*\n- 1 Mark: Correct medical use.\n- 1 Mark: Mention of ionising property.\n- 1 Mark: Risk of mutation/cancer." },
    { marks: 3, q: "Calculate the critical angle for a diamond with a refractive index of 2.42.", a: "sin c = 1 / n\nsin c = 1 / 2.42\nsin c = 0.413\nc = sin⁻¹(0.413) = 24.4°\n\n*Marking Scheme:*\n- 1 Mark: Correct formula use.\n- 1 Mark: Correct calculation of 1/n.\n- 1 Mark: Final answer in degrees." },
    { marks: 3, q: "Explain how a loudspeaker converts an electrical signal into sound waves.", a: "An alternating current flows through a coil in a magnetic field, creating a varying force (motor effect). This causes a paper cone to vibrate back and forth, creating longitudinal pressure waves in the air.\n\n*Marking Scheme:*\n- 1 Mark: AC in a coil creates a magnetic field/force.\n- 1 Mark: Vibration of the cone.\n- 1 Mark: Creation of longitudinal/sound waves." },
    { marks: 3, q: "Describe the properties of an image formed by a plane mirror.", a: "The image is virtual, upright, the same size as the object, and laterally inverted (left-right reversed). It is also the same distance behind the mirror as the object is in front.\n\n*Marking Scheme:*\n- 1 Mark: Virtual and upright.\n- 1 Mark: Same size and distance.\n- 1 Mark: Laterally inverted." },
    { marks: 3, q: "Explain why microwave ovens can be dangerous if not shielded correctly.", a: "Microwaves have a similar frequency to the natural vibrations of water molecules. They cause internal heating of body tissues by vibrating water molecules in cells, which can cause internal burns.\n\n*Marking Scheme:*\n- 1 Mark: Absorption by water molecules.\n- 1 Mark: Internal heating of tissues.\n- 1 Mark: Risk of internal burns." }
  ],
  4: [ // Energy Resources - Edexcel IGCSE
    { marks: 1, q: "State the principle of conservation of energy.", a: "Energy cannot be created or destroyed, only transferred from one store to another.\n\n*Marking Scheme:*\n- 1 Mark: Correct statement of conservation." },
    { marks: 1, q: "Define 'Efficiency'.", a: "The proportion of total energy input that is converted into useful energy output.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "Name one non-renewable energy resource.", a: "Coal / Oil / Natural Gas / Nuclear fuel.\n\n*Marking Scheme:*\n- 1 Mark: Any correct non-renewable resource." },
    { marks: 1, q: "Name one renewable energy resource.", a: "Wind / Solar / Tidal / Hydroelectric / Geothermal / Biomass.\n\n*Marking Scheme:*\n- 1 Mark: Any correct renewable resource." },
    { marks: 1, q: "State the standard unit for energy.", a: "Joule (J).\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 1, q: "State the standard unit for power.", a: "Watt (W).\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 1, q: "State the formula for work done.", a: "Work done = Force × distance moved (W = Fd).\n\n*Marking Scheme:*\n- 1 Mark: Correct formula." },
    { marks: 1, q: "What energy store is increased when an object is heated?", a: "Thermal energy store.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "What energy store is increased when an object is stretched?", a: "Elastic potential energy store.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "State the formula for efficiency.", a: "Efficiency = (Useful energy output / Total energy input) × 100%.\n\n*Marking Scheme:*\n- 1 Mark: Correct formula." },
    { marks: 2, q: "Calculate the work done when a force of 50 N moves an object 10 m in the direction of the force.", a: "Work done = Force × distance\nWork done = 50 × 10\nWork done = 500 J\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "A 100 W light bulb is switched on for 30 seconds. Calculate the energy used.", a: "Energy = Power × time\nEnergy = 100 × 30\nEnergy = 3000 J (or 3 kJ)\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Explain why thermal insulation is used in the lofts of houses.", a: "Insulation traps a layer of air, which is a poor conductor. This reduces heat loss by conduction and convection from the house.\n\n*Marking Scheme:*\n- 1 Mark: Traps air/poor conductor.\n- 1 Mark: Reduces heat loss by conduction/convection." },
    { marks: 2, q: "Describe how a wind turbine generates electricity.", a: "The wind turns the blades, which rotate a generator. The generator converts kinetic energy into electrical energy.\n\n*Marking Scheme:*\n- 1 Mark: Wind turns blades/generator.\n- 1 Mark: Kinetic to electrical energy transfer." },
    { marks: 2, q: "A machine has a total energy input of 500 J and a useful energy output of 350 J. Calculate its efficiency.", a: "Efficiency = (350 / 500) × 100\nEfficiency = 70%\n\n*Marking Scheme:*\n- 1 Mark: Correct calculation (0.7).\n- 1 Mark: Final answer as percentage." },
    { marks: 2, q: "State two disadvantages of using fossil fuels to generate electricity.", a: "1. They release carbon dioxide, which contributes to global warming.\n2. They are non-renewable and will eventually run out.\n\n*Marking Scheme:*\n- 1 Mark: CO2/Global warming.\n- 1 Mark: Non-renewable/Running out." },
    { marks: 2, q: "State two advantages of using solar power.", a: "1. It is a renewable energy resource.\n2. It does not produce greenhouse gases during operation.\n\n*Marking Scheme:*\n- 1 Mark: Renewable.\n- 1 Mark: No greenhouse gases/pollution." },
    { marks: 2, q: "A 5 kg mass is at a height of 2 m. Calculate its gravitational potential energy (g = 10 N/kg).", a: "GPE = m × g × h\nGPE = 5 × 10 × 2\nGPE = 100 J\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "A car of mass 1000 kg moves at a speed of 10 m/s. Calculate its kinetic energy.", a: "KE = ½ × m × v²\nKE = 0.5 × 1000 × 10²\nKE = 50,000 J (or 50 kJ)\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Describe the energy transfers that occur in a battery-powered torch when it is switched on.", a: "Chemical energy in the battery is transferred to electrical energy in the wires, which is then transferred to light energy (useful) and thermal energy (wasted) in the bulb.\n\n*Marking Scheme:*\n- 1 Mark: Chemical to electrical.\n- 1 Mark: Electrical to light/thermal." },
    { marks: 3, q: "Describe the energy transfers that take place in a hydroelectric power station.", a: "Water stored high up has gravitational potential energy. As it falls, this is transferred to kinetic energy of the water. The moving water turns a turbine, transferring kinetic energy to a generator, which produces electrical energy.\n\n*Marking Scheme:*\n- 1 Mark: GPE of stored water.\n- 1 Mark: Kinetic energy of falling water/turbine.\n- 1 Mark: Electrical energy from generator." },
    { marks: 3, q: "Explain how heat is transferred by convection in a liquid being heated from below.", a: "The liquid near the heat source expands and becomes less dense. This less dense liquid rises. Cooler, denser liquid sinks to take its place, creating a convection current.\n\n*Marking Scheme:*\n- 1 Mark: Liquid expands/becomes less dense.\n- 1 Mark: Less dense liquid rises.\n- 1 Mark: Cooler liquid sinks/convection current." },
    { marks: 3, q: "A 2 kg ball is dropped from a height of 5 m. Calculate its velocity just before hitting the ground (g = 10 N/kg, ignore air resistance).", a: "1. GPE lost = mgh = 2 × 10 × 5 = 100 J\n2. KE gained = GPE lost = 100 J\n3. v = √(2 × KE / m) = √(200 / 2) = 10 m/s\n\n*Marking Scheme:*\n- 1 Mark: Calculate GPE (100 J).\n- 1 Mark: Equate KE to GPE.\n- 1 Mark: Final velocity (10 m/s)." },
    { marks: 3, q: "Discuss the environmental impact of using coal-fired power stations to generate electricity.", a: "Coal releases CO2, a greenhouse gas that contributes to climate change. It also releases sulfur dioxide, which causes acid rain. Mining coal can also destroy habitats and cause local pollution.\n\n*Marking Scheme:*\n- 1 Mark: CO2/Climate change.\n- 1 Mark: SO2/Acid rain.\n- 1 Mark: Mining/Habitat destruction." },
    { marks: 3, q: "A heater has a power of 2 kW and is 90% efficient. Calculate the useful energy it provides in 5 minutes.", a: "1. Total energy = Power × time = 2000 × (5 × 60) = 600,000 J\n2. Useful energy = Efficiency × Total energy = 0.9 × 600,000\n3. Useful energy = 540,000 J (or 540 kJ)\n\n*Marking Scheme:*\n- 1 Mark: Calculate total energy (600,000 J).\n- 1 Mark: Apply efficiency (0.9).\n- 1 Mark: Final answer with units." },
    { marks: 3, q: "Explain how a vacuum flask reduces heat transfer by conduction, convection, and radiation.", a: "The vacuum prevents conduction and convection as they require particles. The silvered surfaces reflect infrared radiation back into the flask, reducing heat loss by radiation.\n\n*Marking Scheme:*\n- 1 Mark: Vacuum stops conduction/convection.\n- 1 Mark: Silvered surfaces reflect radiation.\n- 1 Mark: Mention of particles/infrared." },
    { marks: 3, q: "Describe the process of nuclear fission and how it is used to release energy in a reactor.", a: "A large nucleus (e.g., Uranium-235) absorbs a neutron and splits into two smaller nuclei, releasing energy and more neutrons. These neutrons can cause further fissions in a chain reaction.\n\n*Marking Scheme:*\n- 1 Mark: Nucleus absorbs neutron and splits.\n- 1 Mark: Release of energy and neutrons.\n- 1 Mark: Chain reaction." },
    { marks: 3, q: "Compare the reliability and environmental impact of wind power and nuclear power.", a: "Wind is unreliable as it depends on weather, but has low environmental impact. Nuclear is very reliable (base load), but produces radioactive waste that is difficult to manage.\n\n*Marking Scheme:*\n- 1 Mark: Wind unreliability vs Nuclear reliability.\n- 1 Mark: Wind low impact vs Nuclear waste.\n- 1 Mark: Mention of managing waste/weather dependence." },
    { marks: 3, q: "A crane lifts a 200 kg crate through a height of 10 m in 20 seconds. Calculate the power of the crane (g = 10 N/kg).", a: "1. Work done = mgh = 200 × 10 × 10 = 20,000 J\n2. Power = Work / time = 20,000 / 20\n3. Power = 1000 W (or 1 kW)\n\n*Marking Scheme:*\n- 1 Mark: Calculate work done (20,000 J).\n- 1 Mark: Use of Power = Work / Time.\n- 1 Mark: Final answer with units." },
    { marks: 3, q: "Explain the difference between renewable and non-renewable energy resources, giving two examples for each.", a: "Renewable resources are replenished as they are used (e.g., solar, wind). Non-renewable resources are finite and will run out (e.g., coal, nuclear).\n\n*Marking Scheme:*\n- 1 Mark: Definition of renewable (replenished).\n- 1 Mark: Definition of non-renewable (finite).\n- 1 Mark: Correct examples for both." }
  ],
  5: [ // States of Matter - Edexcel IGCSE
    { marks: 1, q: "State the formula for density.", a: "Density = Mass / Volume (ρ = m / V).\n\n*Marking Scheme:*\n- 1 Mark: Correct formula." },
    { marks: 1, q: "State the standard unit for pressure.", a: "Pascal (Pa) or Newtons per square metre (N/m²).\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 1, q: "Define 'Pressure'.", a: "The force acting per unit area.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "What is the temperature of absolute zero in degrees Celsius?", a: "-273 °C.\n\n*Marking Scheme:*\n- 1 Mark: Correct temperature." },
    { marks: 1, q: "State the formula for pressure in a liquid.", a: "Pressure = height × density × g (p = hρg).\n\n*Marking Scheme:*\n- 1 Mark: Correct formula." },
    { marks: 1, q: "What happens to the average speed of particles as temperature increases?", a: "The average speed of the particles increases.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification of increase." },
    { marks: 1, q: "Define 'Specific Heat Capacity'.", a: "The energy required to change the temperature of 1 kg of a substance by 1 °C.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "What is meant by 'Evaporation'?", a: "The escape of higher-energy particles from the surface of a liquid to form a gas.\n\n*Marking Scheme:*\n- 1 Mark: Reference to surface or high-energy particles." },
    { marks: 1, q: "State the relationship between pressure and volume for a fixed mass of gas at constant temperature (Boyle's Law).", a: "Pressure × Volume = Constant (p₁V₁ = p₂V₂).\n\n*Marking Scheme:*\n- 1 Mark: Correct relationship." },
    { marks: 1, q: "State the standard unit for density.", a: "kg/m³ (kilograms per cubic metre) or g/cm³.\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 2, q: "Calculate the density of a 500 g block with a volume of 200 cm³.", a: "Density = Mass / Volume\nDensity = 500 / 200\nDensity = 2.5 g/cm³\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "A force of 100 N acts on an area of 0.5 m². Calculate the pressure.", a: "Pressure = Force / Area\nPressure = 100 / 0.5\nPressure = 200 Pa\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Explain why a person wearing snowshoes doesn't sink into the snow as much as someone in normal boots.", a: "Snowshoes have a much larger area. Since Pressure = Force / Area, a larger area reduces the pressure exerted on the snow.\n\n*Marking Scheme:*\n- 1 Mark: Mention of larger area.\n- 1 Mark: Reference to reduced pressure." },
    { marks: 2, q: "Calculate the pressure at the bottom of a 5 m deep pool (density of water = 1000 kg/m³, g = 10 N/kg).", a: "p = h × ρ × g\np = 5 × 1000 × 10\np = 50,000 Pa (or 50 kPa)\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Convert 27 °C into Kelvin.", a: "T(K) = T(°C) + 273\nT = 27 + 273\nT = 300 K\n\n*Marking Scheme:*\n- 1 Mark: Mention of adding 273.\n- 1 Mark: Correct final value." },
    { marks: 2, q: "Describe the arrangement and motion of particles in a solid.", a: "Particles are closely packed in a regular lattice arrangement and vibrate about fixed positions.\n\n*Marking Scheme:*\n- 1 Mark: Closely packed/regular arrangement.\n- 1 Mark: Vibrate about fixed positions." },
    { marks: 2, q: "Describe the arrangement and motion of particles in a gas.", a: "Particles are far apart with no regular arrangement and move randomly at high speeds.\n\n*Marking Scheme:*\n- 1 Mark: Far apart/no arrangement.\n- 1 Mark: Random/high-speed motion." },
    { marks: 2, q: "Explain why gases can be compressed but solids cannot.", a: "In gases, there are large spaces between particles that can be reduced. In solids, particles are already touching with no space to move closer.\n\n*Marking Scheme:*\n- 1 Mark: Space between gas particles.\n- 1 Mark: Particles touching in solids." },
    { marks: 2, q: "A gas has a volume of 2 m³ at a pressure of 100 kPa. Calculate the volume if the pressure increases to 200 kPa (constant temperature).", a: "p₁V₁ = p₂V₂\n100 × 2 = 200 × V₂\n200 = 200 × V₂\nV₂ = 1 m³\n\n*Marking Scheme:*\n- 1 Mark: Correct use of pV = constant.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Calculate the energy required to heat 2 kg of water (c = 4200 J/kg°C) by 10 °C.", a: "Q = m × c × ΔT\nQ = 2 × 4200 × 10\nQ = 84,000 J (or 84 kJ)\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 3, q: "Describe an experiment to determine the density of an irregularly shaped object.", a: "Measure the mass of the object using a balance. Submerge the object in a displacement (eureka) can filled with water. Measure the volume of the displaced water using a measuring cylinder. Density = Mass / Volume.\n\n*Marking Scheme:*\n- 1 Mark: Measure mass with balance.\n- 1 Mark: Measure volume using displacement/measuring cylinder.\n- 1 Mark: Use of density = mass / volume." },
    { marks: 3, q: "Explain how the pressure of a gas in a container is produced in terms of particle motion.", a: "Gas particles move randomly and collide with the walls of the container. These collisions exert a force on the walls. Pressure is the total force exerted per unit area of the walls.\n\n*Marking Scheme:*\n- 1 Mark: Particles collide with walls.\n- 1 Mark: Collisions exert a force.\n- 1 Mark: Pressure = Force / Area." },
    { marks: 3, q: "Explain why the pressure of a gas increases when it is heated at a constant volume.", a: "Heating increases the kinetic energy and speed of the particles. Particles collide with the walls more frequently and with more force. This increases the total force on the walls, increasing pressure.\n\n*Marking Scheme:*\n- 1 Mark: Particles move faster/more KE.\n- 1 Mark: More frequent collisions.\n- 1 Mark: More forceful collisions." },
    { marks: 3, q: "Describe the changes that occur when a solid melts into a liquid in terms of particles and energy.", a: "Energy is absorbed to break the bonds between particles. The regular lattice structure is lost as particles begin to slide over each other. The potential energy increases while the temperature remains constant.\n\n*Marking Scheme:*\n- 1 Mark: Energy used to break bonds.\n- 1 Mark: Loss of regular structure/particles slide.\n- 1 Mark: Increase in potential energy." },
    { marks: 3, q: "A block of ice is heated from -10 °C to 0 °C, then it melts. Explain why the temperature stays constant while it is melting.", a: "The energy being supplied is used to break the intermolecular bonds between the water molecules rather than increasing their kinetic energy. Since temperature is a measure of average kinetic energy, it remains constant.\n\n*Marking Scheme:*\n- 1 Mark: Energy used to break bonds.\n- 1 Mark: No increase in kinetic energy.\n- 1 Mark: Temperature relates to kinetic energy." },
    { marks: 3, q: "Explain the difference between evaporation and boiling.", a: "Boiling occurs throughout the liquid at a specific temperature (boiling point). Evaporation occurs only at the surface and can happen at any temperature below the boiling point. Evaporation causes cooling of the remaining liquid.\n\n*Marking Scheme:*\n- 1 Mark: Boiling throughout vs Evaporation at surface.\n- 1 Mark: Fixed temperature vs any temperature.\n- 1 Mark: Cooling effect of evaporation." },
    { marks: 3, q: "A gas at 20 °C has a pressure of 100 kPa. Calculate its pressure at 100 °C (constant volume).", a: "1. Convert to Kelvin: T₁ = 293 K, T₂ = 373 K\n2. p₁/T₁ = p₂/T₂\n3. 100 / 293 = p₂ / 373\n4. p₂ = (100 × 373) / 293 = 127.3 kPa\n\n*Marking Scheme:*\n- 1 Mark: Conversion to Kelvin.\n- 1 Mark: Correct use of p/T = constant.\n- 1 Mark: Final answer with units." },
    { marks: 3, q: "Describe how to measure the specific heat capacity of a metal block.", a: "Measure the mass of the block. Use an electric heater to supply a measured amount of energy (using a joulemeter). Measure the initial and final temperature with a thermometer. Use c = Q / (mΔT).\n\n*Marking Scheme:*\n- 1 Mark: Measure mass and energy (joulemeter).\n- 1 Mark: Measure temperature change.\n- 1 Mark: Use of c = Q / (mΔT)." },
    { marks: 3, q: "Explain how the Brownian motion of smoke particles provides evidence for the kinetic theory of matter.", a: "Smoke particles move randomly because they are being hit by much smaller, fast-moving air molecules that are invisible. This shows that air is made of particles in constant random motion.\n\n*Marking Scheme:*\n- 1 Mark: Random motion of smoke particles.\n- 1 Mark: Collisions with invisible air molecules.\n- 1 Mark: Evidence for air particles in motion." },
    { marks: 3, q: "A diver is 20 m underwater. Calculate the total pressure acting on them (Atmospheric pressure = 100 kPa, density of water = 1000 kg/m³, g = 10 N/kg).", a: "1. Water pressure = hρg = 20 × 1000 × 10 = 200,000 Pa (200 kPa)\n2. Total pressure = Water pressure + Atmospheric pressure\n3. Total pressure = 200 + 100 = 300 kPa\n\n*Marking Scheme:*\n- 1 Mark: Calculate water pressure (200 kPa).\n- 1 Mark: Add atmospheric pressure.\n- 1 Mark: Final answer with units." }
  ],
  6: [ // Magnetism and Electromagnetism - Edexcel IGCSE
    { marks: 1, q: "State the law of magnetism regarding poles.", a: "Like poles repel; opposite poles attract.\n\n*Marking Scheme:*\n- 1 Mark: Correct statement of repulsion and attraction." },
    { marks: 1, q: "Name two magnetic materials.", a: "Iron / Steel / Nickel / Cobalt.\n\n*Marking Scheme:*\n- 1 Mark: Any two correct materials." },
    { marks: 1, q: "What is a 'hard' magnetic material?", a: "A material that is difficult to magnetise but retains its magnetism well (e.g., steel).\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "What is a 'soft' magnetic material?", a: "A material that is easy to magnetise and demagnetise (e.g., soft iron).\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "In which direction do magnetic field lines always point?", a: "From North to South.\n\n*Marking Scheme:*\n- 1 Mark: Correct direction." },
    { marks: 1, q: "What is an electromagnet?", a: "A magnet consisting of a coil of wire that acts as a magnet only when an electric current passes through it.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "State the rule used to find the direction of the magnetic field around a straight wire.", a: "Right-hand grip rule.\n\n*Marking Scheme:*\n- 1 Mark: Correct rule name." },
    { marks: 1, q: "State the rule used to find the direction of the force on a current-carrying wire in a magnetic field.", a: "Fleming's Left-Hand Rule.\n\n*Marking Scheme:*\n- 1 Mark: Correct rule name." },
    { marks: 1, q: "What is the 'motor effect'?", a: "The force experienced by a current-carrying wire when placed in a magnetic field.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "State one way to increase the strength of an electromagnet.", a: "Increase the current / Increase the number of turns in the coil / Add a soft iron core.\n\n*Marking Scheme:*\n- 1 Mark: Any one correct method." },
    { marks: 2, q: "Describe how to use a plotting compass to show the magnetic field pattern of a bar magnet.", a: "Place the compass near the magnet and mark the direction of the needle. Move the compass to the mark and repeat. Join the marks to form field lines.\n\n*Marking Scheme:*\n- 1 Mark: Marking needle direction.\n- 1 Mark: Repeating and joining marks." },
    { marks: 2, q: "Explain the difference between permanent magnets and induced magnets.", a: "Permanent magnets produce their own magnetic field. Induced magnets only become magnetic when placed in a magnetic field.\n\n*Marking Scheme:*\n- 1 Mark: Permanent produces own field.\n- 1 Mark: Induced requires external field." },
    { marks: 2, q: "Describe the magnetic field inside a solenoid.", a: "The field is strong and uniform (parallel lines).\n\n*Marking Scheme:*\n- 1 Mark: Strong.\n- 1 Mark: Uniform/Parallel." },
    { marks: 2, q: "State two ways to increase the force on a wire in the motor effect.", a: "1. Increase the current.\n2. Increase the strength of the magnetic field.\n\n*Marking Scheme:*\n- 1 Mark: Increase current.\n- 1 Mark: Increase field strength." },
    { marks: 2, q: "Explain why a transformer only works with alternating current (AC).", a: "AC produces a continuously changing magnetic field in the core, which is necessary to induce a voltage in the secondary coil.\n\n*Marking Scheme:*\n- 1 Mark: Changing magnetic field.\n- 1 Mark: Induction of voltage." },
    { marks: 2, q: "State the formula relating the voltages and number of turns in a transformer.", a: "Vp / Vs = Np / Ns (Primary voltage / Secondary voltage = Primary turns / Secondary turns).\n\n*Marking Scheme:*\n- 1 Mark: Correct formula.\n- 1 Mark: Identification of terms." },
    { marks: 2, q: "A transformer has 100 turns on the primary and 500 turns on the secondary. If the input is 12 V, calculate the output voltage.", a: "Vs = Vp × (Ns / Np)\nVs = 12 × (500 / 100)\nVs = 60 V\n\n*Marking Scheme:*\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "Describe how to reverse the direction of the force in the motor effect.", a: "Reverse the direction of the current OR reverse the direction of the magnetic field.\n\n*Marking Scheme:*\n- 1 Mark: Reverse current.\n- 1 Mark: Reverse field." },
    { marks: 2, q: "What is electromagnetic induction?", a: "The creation of a voltage (and current) in a conductor when it moves through a magnetic field or when the magnetic field through it changes.\n\n*Marking Scheme:*\n- 1 Mark: Creation of voltage.\n- 1 Mark: Relative motion or changing field." },
    { marks: 2, q: "State two ways to increase the induced voltage in a generator.", a: "1. Rotate the coil faster.\n2. Use a stronger magnet / more turns in the coil.\n\n*Marking Scheme:*\n- 1 Mark: Faster rotation.\n- 1 Mark: Stronger magnet/more turns." },
    { marks: 3, q: "Explain how a simple DC motor works.", a: "A current-carrying coil in a magnetic field experiences a force (motor effect). The forces on opposite sides of the coil are in opposite directions, causing it to rotate. A split-ring commutator reverses the current every half turn to keep it rotating in the same direction.\n\n*Marking Scheme:*\n- 1 Mark: Current in coil + magnetic field = force.\n- 1 Mark: Opposite forces cause rotation.\n- 1 Mark: Role of split-ring commutator." },
    { marks: 3, q: "Describe the structure and function of a step-up transformer.", a: "It has more turns on the secondary coil than the primary. It increases the voltage and decreases the current, which reduces energy loss as heat in transmission cables.\n\n*Marking Scheme:*\n- 1 Mark: More turns on secondary.\n- 1 Mark: Increases voltage.\n- 1 Mark: Reduces energy loss in cables." },
    { marks: 3, q: "Explain how a loudspeaker uses the motor effect to produce sound.", a: "An alternating current in the coil creates a varying magnetic field. This interacts with the permanent magnet, producing a varying force that causes the cone to vibrate. These vibrations create sound waves in the air.\n\n*Marking Scheme:*\n- 1 Mark: AC creates varying magnetic field.\n- 1 Mark: Interaction with permanent magnet/force.\n- 1 Mark: Cone vibrates to create sound waves." },
    { marks: 3, q: "Describe an experiment to show the magnetic field pattern around a straight current-carrying wire.", a: "Pass a wire through a piece of card. Sprinkle iron filings on the card and tap it, or use a plotting compass to mark the field direction. The pattern is concentric circles around the wire.\n\n*Marking Scheme:*\n- 1 Mark: Setup with wire and card.\n- 1 Mark: Use of iron filings or compass.\n- 1 Mark: Description of concentric circles." },
    { marks: 3, q: "A transformer is 100% efficient. It has an input of 230 V and 0.5 A. If the output voltage is 12 V, calculate the output current.", a: "1. Input power = Vp × Ip = 230 × 0.5 = 115 W\n2. Output power = Input power = 115 W\n3. Is = P / Vs = 115 / 12 = 9.58 A\n\n*Marking Scheme:*\n- 1 Mark: Calculate input power (115 W).\n- 1 Mark: Equate output power to input power.\n- 1 Mark: Final current with units." },
    { marks: 3, q: "Explain how a bicycle dynamo generates electricity.", a: "A magnet is rotated inside a coil of wire (or vice versa). As the magnet turns, the magnetic field through the coil changes, inducing a voltage and current in the wire (electromagnetic induction).\n\n*Marking Scheme:*\n- 1 Mark: Rotating magnet/coil.\n- 1 Mark: Changing magnetic field.\n- 1 Mark: Induction of voltage/current." },
    { marks: 3, q: "Describe the role of transformers in the National Grid.", a: "Step-up transformers increase voltage for long-distance transmission to reduce energy loss. Step-down transformers decrease voltage to safe levels for use in homes and factories.\n\n*Marking Scheme:*\n- 1 Mark: Step-up for transmission (reduce loss).\n- 1 Mark: Step-down for safety/homes.\n- 1 Mark: Mention of efficiency/safety." },
    { marks: 3, q: "Explain why the core of a transformer is made of soft iron.", a: "Soft iron is a soft magnetic material, meaning it is easily magnetised and demagnetised. This allows the magnetic field to change direction rapidly with the alternating current, ensuring efficient induction.\n\n*Marking Scheme:*\n- 1 Mark: Soft magnetic material.\n- 1 Mark: Easy magnetisation/demagnetisation.\n- 1 Mark: Efficient field reversal/induction." },
    { marks: 3, q: "State Fleming's Left-Hand Rule and explain what each finger represents.", a: "Thumb: Direction of Force (Motion). First Finger: Direction of Magnetic Field (N to S). Second Finger: Direction of Current (+ to -).\n\n*Marking Scheme:*\n- 1 Mark: Thumb = Force/Motion.\n- 1 Mark: First Finger = Field.\n- 1 Mark: Second Finger = Current." },
    { marks: 3, q: "A step-down transformer has 2000 turns on the primary and 100 turns on the secondary. If the output is 12 V, calculate the input voltage and the turns ratio.", a: "1. Vp = Vs × (Np / Ns) = 12 × (2000 / 100) = 240 V\n2. Turns ratio (Np:Ns) = 20:1\n\n*Marking Scheme:*\n- 1 Mark: Correct calculation of Vp (240 V).\n- 1 Mark: Correct turns ratio.\n- 1 Mark: Final answers with units." }
  ],
  7: [ // Radioactivity and Particles - Edexcel IGCSE
    { marks: 1, q: "State the three types of ionising radiation.", a: "Alpha (α), Beta (β), and Gamma (γ).\n\n*Marking Scheme:*\n- 1 Mark: All three correct." },
    { marks: 1, q: "What is an alpha particle made of?", a: "Two protons and two neutrons (a Helium nucleus).\n\n*Marking Scheme:*\n- 1 Mark: Correct composition." },
    { marks: 1, q: "What is a beta particle?", a: "A high-speed electron emitted from the nucleus.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "Which type of radiation is the most ionising?", a: "Alpha radiation.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "Which type of radiation is the most penetrating?", a: "Gamma radiation.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "Define 'Half-life'.", a: "The time taken for the activity of a radioactive source to decrease by half.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "What is the unit for the activity of a radioactive source?", a: "Becquerel (Bq).\n\n*Marking Scheme:*\n- 1 Mark: Correct unit." },
    { marks: 1, q: "What is background radiation?", a: "Radiation that is present all around us from natural and man-made sources.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "State one natural source of background radiation.", a: "Cosmic rays / Radon gas / Rocks / Food (e.g., bananas).\n\n*Marking Scheme:*\n- 1 Mark: Any correct natural source." },
    { marks: 1, q: "What instrument is used to detect ionising radiation?", a: "Geiger-Müller (GM) tube.\n\n*Marking Scheme:*\n- 1 Mark: Correct instrument." },
    { marks: 2, q: "Explain why an atom has no overall charge.", a: "It has an equal number of protons (positive) and electrons (negative), which cancel each other out.\n\n*Marking Scheme:*\n- 1 Mark: Equal number of protons and electrons.\n- 1 Mark: Charges cancel out." },
    { marks: 2, q: "Define 'Isotope'.", a: "Atoms of the same element with the same number of protons but a different number of neutrons.\n\n*Marking Scheme:*\n- 1 Mark: Same protons.\n- 1 Mark: Different neutrons." },
    { marks: 2, q: "Describe the process of beta decay in terms of protons and neutrons.", a: "A neutron in the nucleus turns into a proton and an electron. The proton stays in the nucleus, and the electron is emitted.\n\n*Marking Scheme:*\n- 1 Mark: Neutron turns to proton + electron.\n- 1 Mark: Proton stays, electron emitted." },
    { marks: 2, q: "Explain why alpha radiation is dangerous if it enters the body.", a: "It is highly ionising, so it can easily damage DNA and cells, potentially leading to cancer.\n\n*Marking Scheme:*\n- 1 Mark: Highly ionising.\n- 1 Mark: Damage to DNA/cells/cancer risk." },
    { marks: 2, q: "State two ways to reduce the risk when handling radioactive sources.", a: "1. Use long-handled tongs to increase distance.\n2. Store sources in lead-lined containers.\n\n*Marking Scheme:*\n- 1 Mark: Increase distance (tongs).\n- 1 Mark: Shielding (lead containers)." },
    { marks: 2, q: "A source has an initial activity of 800 Bq. Calculate its activity after two half-lives.", a: "After 1 half-life: 400 Bq. After 2 half-lives: 200 Bq.\n\n*Marking Scheme:*\n- 1 Mark: Correct first step (400).\n- 1 Mark: Final answer (200 Bq)." },
    { marks: 2, q: "Explain the difference between contamination and irradiation.", a: "Contamination is the presence of radioactive material on or in an object. Irradiation is exposure to radiation from an external source.\n\n*Marking Scheme:*\n- 1 Mark: Contamination = material present.\n- 1 Mark: Irradiation = exposure to waves/particles." },
    { marks: 2, q: "Describe the structure of an atom in terms of protons, neutrons, and electrons.", a: "Protons and neutrons are in the central nucleus. Electrons orbit the nucleus in shells.\n\n*Marking Scheme:*\n- 1 Mark: Nucleus contains protons/neutrons.\n- 1 Mark: Electrons in shells/orbiting." },
    { marks: 2, q: "State two uses of radioactivity in industry.", a: "1. Thickness monitoring (e.g., paper/foil).\n2. Leak detection in underground pipes.\n\n*Marking Scheme:*\n- 1 Mark: Thickness monitoring.\n- 1 Mark: Leak detection." },
    { marks: 2, q: "Explain why gamma radiation is used for medical imaging.", a: "It is highly penetrating, so it can pass out of the body to be detected by a camera, and it is less ionising than alpha or beta.\n\n*Marking Scheme:*\n- 1 Mark: Highly penetrating (leaves body).\n- 1 Mark: Less ionising (lower risk)." },
    { marks: 3, q: "Describe the Geiger-Marsden (Rutherford) alpha scattering experiment and its conclusions.", a: "Alpha particles were fired at thin gold foil. Most passed through (atom is mostly empty space). Some were deflected (nucleus is positive). A few bounced back (nucleus is small and dense).\n\n*Marking Scheme:*\n- 1 Mark: Mostly empty space (passed through).\n- 1 Mark: Positive nucleus (deflected).\n- 1 Mark: Small, dense nucleus (bounced back)." },
    { marks: 3, q: "Explain how carbon-14 dating is used to determine the age of ancient organic materials.", a: "Living things absorb C-14. When they die, they stop absorbing it and the C-14 decays. By measuring the remaining activity and knowing the half-life, the age can be calculated.\n\n*Marking Scheme:*\n- 1 Mark: Absorption stops at death.\n- 1 Mark: C-14 decays over time.\n- 1 Mark: Measure activity + use half-life to find age." },
    { marks: 3, q: "Describe the process of nuclear fission in a reactor, including the role of control rods and moderator.", a: "U-235 absorbs a neutron and splits. The moderator slows down neutrons to allow further fissions. Control rods absorb excess neutrons to regulate the chain reaction.\n\n*Marking Scheme:*\n- 1 Mark: Fission of U-235.\n- 1 Mark: Moderator slows neutrons.\n- 1 Mark: Control rods absorb neutrons/control rate." },
    { marks: 3, q: "Explain the process of nuclear fusion and the conditions required for it to occur.", a: "Two small nuclei (e.g., Hydrogen) join to form a larger nucleus, releasing energy. This requires extremely high temperatures and pressures to overcome the electrostatic repulsion between nuclei.\n\n*Marking Scheme:*\n- 1 Mark: Joining of small nuclei.\n- 1 Mark: Release of energy.\n- 1 Mark: High temp/pressure required." },
    { marks: 3, q: "Compare the properties of alpha, beta, and gamma radiation in terms of mass, charge, and ionising power.", a: "Alpha: Mass 4, Charge +2, Highly ionising. Beta: Mass ~0, Charge -1, Moderately ionising. Gamma: Mass 0, Charge 0, Weakly ionising.\n\n*Marking Scheme:*\n- 1 Mark: Correct alpha properties.\n- 1 Mark: Correct beta properties.\n- 1 Mark: Correct gamma properties." },
    { marks: 3, q: "A radioactive isotope has a half-life of 6 hours. If the initial mass is 48g, calculate the mass remaining after 24 hours.", a: "1. Number of half-lives = 24 / 6 = 4.\n2. Mass after 1: 24g, 2: 12g, 3: 6g, 4: 3g.\n3. Final mass = 3g.\n\n*Marking Scheme:*\n- 1 Mark: Find number of half-lives (4).\n- 1 Mark: Correct halving steps.\n- 1 Mark: Final answer with units." },
    { marks: 3, q: "Describe the dangers of ionising radiation to living organisms and how these risks can be minimised.", a: "Radiation can cause mutations, cell death, and cancer. Risks are minimised by using shielding (lead), increasing distance (tongs), and limiting exposure time.\n\n*Marking Scheme:*\n- 1 Mark: Dangers (mutations/cancer).\n- 1 Mark: Shielding/Distance.\n- 1 Mark: Limiting time/Monitoring (film badges)." },
    { marks: 3, q: "Explain how a smoke detector uses alpha radiation.", a: "Alpha particles ionise the air, allowing a current to flow. Smoke particles block the alpha particles, reducing the ionisation and the current. The drop in current triggers the alarm.\n\n*Marking Scheme:*\n- 1 Mark: Alpha ionises air (current flows).\n- 1 Mark: Smoke blocks alpha particles.\n- 1 Mark: Current drop triggers alarm." },
    { marks: 3, q: "Describe the role of shielding in a nuclear reactor.", a: "The reactor core is surrounded by thick concrete and lead. This absorbs high-energy neutrons and gamma radiation, preventing them from escaping and harming workers or the environment.\n\n*Marking Scheme:*\n- 1 Mark: Thick concrete/lead.\n- 1 Mark: Absorbs neutrons/gamma.\n- 1 Mark: Prevents escape/protects workers." },
    { marks: 3, q: "Explain why nuclear fusion is not yet a viable source of energy on Earth despite being the process that powers the sun.", a: "It requires extremely high temperatures (millions of degrees) to overcome repulsion. Containing this hot plasma is very difficult and currently requires more energy than the process produces.\n\n*Marking Scheme:*\n- 1 Mark: High temperature needed for repulsion.\n- 1 Mark: Containment of plasma is difficult.\n- 1 Mark: Net energy gain not yet achieved." }
  ],
  8: [ // Astrophysics - Edexcel IGCSE
    { marks: 1, q: "Name the galaxy that contains our Solar System.", a: "The Milky Way.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "What is the force that keeps planets in orbit around the Sun?", a: "Gravitational force (Gravity).\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "Define 'Orbital Period'.", a: "The time taken for an object to complete one full orbit.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "Which planet in our solar system is closest to the Sun?", a: "Mercury.\n\n*Marking Scheme:*\n- 1 Mark: Correct identification." },
    { marks: 1, q: "What is a 'Comet'?", a: "A ball of ice and dust that orbits the Sun in a highly elliptical orbit.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "State the relationship between orbital speed, orbital radius, and time period.", a: "Orbital speed = (2 × π × orbital radius) / time period (v = 2πr / T).\n\n*Marking Scheme:*\n- 1 Mark: Correct formula." },
    { marks: 1, q: "What is a 'Universe'?", a: "A large collection of billions of galaxies.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "What is a 'Galaxy'?", a: "A large collection of billions of stars.\n\n*Marking Scheme:*\n- 1 Mark: Correct definition." },
    { marks: 1, q: "What color are the hottest stars?", a: "Blue.\n\n*Marking Scheme:*\n- 1 Mark: Correct color." },
    { marks: 1, q: "What color are the coolest stars?", a: "Red.\n\n*Marking Scheme:*\n- 1 Mark: Correct color." },
    { marks: 2, q: "Explain why the gravitational field strength (g) is different on different planets.", a: "It depends on the mass of the planet and its radius. A larger mass or smaller radius results in a stronger gravitational field.\n\n*Marking Scheme:*\n- 1 Mark: Depends on mass.\n- 1 Mark: Depends on radius." },
    { marks: 2, q: "Describe the orbit of a comet.", a: "It is highly elliptical, with the Sun at one focus. It travels much faster when it is closer to the Sun.\n\n*Marking Scheme:*\n- 1 Mark: Highly elliptical.\n- 1 Mark: Faster near the Sun." },
    { marks: 2, q: "Explain the difference between the orbits of planets and moons.", a: "Planets orbit the Sun in near-circular orbits. Moons orbit planets in near-circular orbits.\n\n*Marking Scheme:*\n- 1 Mark: Planets orbit Sun.\n- 1 Mark: Moons orbit planets." },
    { marks: 2, q: "Calculate the orbital speed of a satellite at a radius of 7000 km with a period of 2 hours.", a: "v = 2πr / T\nr = 7,000,000 m, T = 7200 s\nv = (2 × 3.14 × 7,000,000) / 7200 = 6105 m/s\n\n*Marking Scheme:*\n- 1 Mark: Correct conversion of units.\n- 1 Mark: Final answer with units." },
    { marks: 2, q: "What is a 'Nebula'?", a: "A large cloud of dust and gas (mainly hydrogen) in space where stars are born.\n\n*Marking Scheme:*\n- 1 Mark: Cloud of dust/gas.\n- 1 Mark: Birthplace of stars." },
    { marks: 2, q: "Describe the 'Main Sequence' stage of a star.", a: "The star is stable because the inward force of gravity is balanced by the outward pressure from nuclear fusion of hydrogen.\n\n*Marking Scheme:*\n- 1 Mark: Stable/Balanced forces.\n- 1 Mark: Hydrogen fusion." },
    { marks: 2, q: "What determines whether a star becomes a White Dwarf or a Supernova?", a: "The initial mass of the star. Low-mass stars become white dwarfs; high-mass stars become supernovae.\n\n*Marking Scheme:*\n- 1 Mark: Initial mass.\n- 1 Mark: Low mass -> White Dwarf, High mass -> Supernova." },
    { marks: 2, q: "Define 'Apparent Magnitude'.", a: "How bright a star appears to be from Earth.\n\n*Marking Scheme:*\n- 1 Mark: Brightness from Earth.\n- 1 Mark: Mention of 'appears'." },
    { marks: 2, q: "Define 'Absolute Magnitude'.", a: "The brightness of a star if it were at a standard distance (10 parsecs) from Earth.\n\n*Marking Scheme:*\n- 1 Mark: Brightness at standard distance.\n- 1 Mark: Mention of 10 parsecs/standard distance." },
    { marks: 2, q: "What is 'Red-shift'?", a: "The increase in the observed wavelength of light from distant galaxies as they move away from us.\n\n*Marking Scheme:*\n- 1 Mark: Increase in wavelength.\n- 1 Mark: Galaxies moving away." },
    { marks: 3, q: "Describe the life cycle of a star with a mass much larger than the Sun.", a: "Nebula -> Protostar -> Main Sequence -> Red Supergiant -> Supernova -> Neutron Star or Black Hole.\n\n*Marking Scheme:*\n- 1 Mark: Nebula to Main Sequence.\n- 1 Mark: Red Supergiant to Supernova.\n- 1 Mark: Neutron Star/Black Hole." },
    { marks: 3, q: "Explain how red-shift provides evidence for the Big Bang theory.", a: "Light from distant galaxies is red-shifted, meaning they are moving away. Further galaxies move faster. This suggests the universe is expanding from a single point.\n\n*Marking Scheme:*\n- 1 Mark: Red-shift means moving away.\n- 1 Mark: Further = faster (Hubble's Law).\n- 1 Mark: Evidence for expansion/Big Bang." },
    { marks: 3, q: "Describe the life cycle of a star with a mass similar to the Sun.", a: "Nebula -> Protostar -> Main Sequence -> Red Giant -> White Dwarf -> Black Dwarf.\n\n*Marking Scheme:*\n- 1 Mark: Nebula to Main Sequence.\n- 1 Mark: Red Giant stage.\n- 1 Mark: White Dwarf to Black Dwarf." },
    { marks: 3, q: "Explain the role of Cosmic Microwave Background Radiation (CMBR) in supporting the Big Bang theory.", a: "CMBR is low-energy microwave radiation that fills the universe. It is the 'afterglow' of the Big Bang, stretched by the expansion of the universe over billions of years.\n\n*Marking Scheme:*\n- 1 Mark: Radiation filling the universe.\n- 1 Mark: Afterglow of Big Bang.\n- 1 Mark: Evidence for expansion/cooling." },
    { marks: 3, q: "Describe how stars are classified using the Hertzsprung-Russell (H-R) diagram.", a: "Stars are plotted by luminosity (y-axis) and temperature (x-axis, decreasing). Most stars fall on the Main Sequence. Red Giants are top-right; White Dwarfs are bottom-left.\n\n*Marking Scheme:*\n- 1 Mark: Luminosity vs Temperature.\n- 1 Mark: Main Sequence position.\n- 1 Mark: Red Giant/White Dwarf positions." },
    { marks: 3, q: "Explain how the temperature of a star can be determined from its color.", a: "Stars emit a range of wavelengths. Hotter stars emit more short-wavelength (blue) light. Cooler stars emit more long-wavelength (red) light. This is called blackbody radiation.\n\n*Marking Scheme:*\n- 1 Mark: Range of wavelengths emitted.\n- 1 Mark: Hot = Blue (short λ).\n- 1 Mark: Cool = Red (long λ)." },
    { marks: 3, q: "A galaxy is moving away at 3000 km/s. If the speed of light is 3 × 10⁵ km/s and the original wavelength is 600 nm, calculate the change in wavelength.", a: "1. Δλ / λ₀ = v / c\n2. Δλ / 600 = 3000 / 300,000\n3. Δλ = 600 × 0.01 = 6 nm\n\n*Marking Scheme:*\n- 1 Mark: Correct formula use.\n- 1 Mark: Correct substitution.\n- 1 Mark: Final answer with units." },
    { marks: 3, q: "Describe the formation of a protostar from a nebula.", a: "Gravity pulls dust and gas together. As the cloud collapses, it becomes denser and hotter as gravitational potential energy is converted into thermal energy. Eventually, it is hot enough for fusion to begin.\n\n*Marking Scheme:*\n- 1 Mark: Gravity pulls cloud together.\n- 1 Mark: Collapse increases density/temp.\n- 1 Mark: Fusion begins." },
    { marks: 3, q: "Explain why a supernova is important for the distribution of elements in the universe.", a: "The extreme temperatures in a supernova allow for the fusion of elements heavier than iron. The explosion then scatters these elements throughout space, where they can form new stars and planets.\n\n*Marking Scheme:*\n- 1 Mark: Fusion of heavy elements (> iron).\n- 1 Mark: Scattering of elements.\n- 1 Mark: Formation of new systems." },
    { marks: 3, q: "Compare the Big Bang theory with the evidence from red-shift and CMBR.", a: "Red-shift shows galaxies are moving away, supporting expansion. CMBR shows the universe was once very hot and has cooled, supporting a single explosive start. Both align with Big Bang predictions.\n\n*Marking Scheme:*\n- 1 Mark: Red-shift = expansion.\n- 1 Mark: CMBR = hot start/cooling.\n- 1 Mark: Conclusion of support for Big Bang." }
  ]
};
